        inventoryService().reserve(event.productId(), event.qty());
    }

    @DltHandler
    public void handleDlt(OrderPlacedEvent event) {
        System.err.println("STOCK RESERVATION PERMANENTLY FAILED: " + event.orderId());
        // Alert ops, save to failed_orders, manual resolution
    }

    // Simulated service (inject in real code):
