import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

record OrderPlacedEvent2(String orderId, String productId, int qty, String email) {}

// Consumer Group 1: inventory-group
@Service
public class InventoryConsumer2 {
    @KafkaListener(topics = "order-placed", groupId = "inventory-group")
    public void reserveStock(OrderPlacedEvent2 event) {
        System.out.printf(
            "[inventory-group] Reserving %d units of %s for order %s%n",
            event.qty(), event.productId(), event.orderId());
        // Both InventoryConsumer and EmailConsumer receive this SAME message
    }
}

// Consumer Group 2: email-group — INDEPENDENT of inventory-group!
@Service
public class EmailConsumer {
    @KafkaListener(topics = "order-placed", groupId = "email-group")
    public void sendConfirmation(OrderPlacedEvent2 event) {
        System.out.printf(
            "[email-group] Sending confirmation to %s for order %s%n",
            event.email(), event.orderId());
        // This group reads from its own offset — if EmailConsumer is slow,
        // it doesn't affect InventoryConsumer's processing at all
    }
}

// Key insight:
// order-placed message: published once by order-service
// inventory-group: reads it once → reserves stock
// email-group: reads it once → sends email
// Both happen independently — fail-safe from each other

