// Test-only listener component with latch:
@Component
class TestTradeConsumer {
    private CountDownLatch latch;
    private final AtomicReference<TradeExecutedEvent> received = new AtomicReference<>();

    void setLatch(CountDownLatch latch) { this.latch = latch; }
    TradeExecutedEvent getReceived()    { return received.get(); }

    @KafkaListener(topics = "trade-events-test", groupId = "test-group")
    public void consume(TradeExecutedEvent event) {
        received.set(event);
        if (latch != null) latch.countDown();  // signal test: done!
    }
}

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@EmbeddedKafka(partitions=1, topics={"trade-events-test"})
@TestPropertySource(properties={
    "spring.kafka.bootstrap-servers=${spring.embedded.kafka.brokers}",
    "spring.kafka.consumer.auto-offset-reset=earliest",
