        TradeExecutedEvent event = new TradeExecutedEvent(
            "TRD-001","U01","TCS",10,3890.0,38900.0,"BUY",java.time.Instant.now());
        kafkaTemplate.send("trade-events-test", "TCS", event);

        // Wait up to 5 seconds — no hardcoded sleep:
        boolean processed = latch.await(5, TimeUnit.SECONDS);
        assertTrue(processed, "Consumer did not process the message within 5 seconds");
        assertEquals("TRD-001", consumer.getReceived().tradeId());
    }
}

