import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Service;

@Service
public class PaymentConsumer {

    @KafkaListener(topics = "payment-events",
                   groupId = "payment-processor")
    public void handlePayment(
            ConsumerRecord<String, PaymentEvent> record,
            Acknowledgment acknowledgment) {  // Injected when ack-mode=manual

        PaymentEvent event = record.value();
        try {
            // Process payment — must fully succeed before acknowledging:
            paymentProcessor().process(event);

            // Only commit offset when processing SUCCEEDED:
            acknowledgment.acknowledge();
            System.out.println("Payment processed and ACKed: " + event.paymentId());

        } catch (Exception e) {
            System.err.println("Payment processing FAILED (no ACK): " + event.paymentId());
            // DO NOT acknowledge → Kafka will redeliver this message
            // After max retries: goes to DLT if configured
        }
    }

    private Object paymentProcessor() {
        return new Object() {
            void process(PaymentEvent e) { System.out.println("Processing: " + e.paymentId()); }
        };
    }
}

