import org.springframework.kafka.annotation.*;
import org.springframework.retry.annotation.Backoff;
import org.springframework.stereotype.Service;
import org.springframework.kafka.test.context.EmbeddedKafka;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.test.context.TestPropertySource;
import java.util.concurrent.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class RetryableConsumer {
    volatile CountDownLatch mainLatch;
    volatile CountDownLatch dltLatch;

    @RetryableTopic(attempts="2", backoff=@Backoff(delay=100))
    @KafkaListener(topics="retry-test-topic", groupId="retry-test-group")
    public void handle(String message) {
        if(mainLatch!=null) mainLatch.countDown();
        throw new RuntimeException("Always fails!");
    }

    @DltHandler
    public void handleDlt(String message) {
        System.out.println("DLT received: " + message);
        if(dltLatch!=null) dltLatch.countDown();
    }
}

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@EmbeddedKafka(partitions=1, topics={"retry-test-topic","retry-test-topic-retry-0","retry-test-topic-dlt"})
@TestPropertySource(properties={
    "spring.kafka.bootstrap-servers=${spring.embedded.kafka.brokers}",
    "spring.kafka.consumer.auto-offset-reset=earliest",
    "spring.kafka.consumer.properties.spring.json.trusted.packages=*"
})
class DltRetryTest {
    @Autowired RetryableConsumer consumer;
    @Autowired KafkaTemplate<String,String> kafkaTemplate;

    @Test
    void afterRetryExhaustion_dltHandlerCalled() throws Exception {
        CountDownLatch mainLatch = new CountDownLatch(2); // 2 attempts
        CountDownLatch dltLatch  = new CountDownLatch(1);
        consumer.mainLatch = mainLatch;
        consumer.dltLatch  = dltLatch;

        kafkaTemplate.send("retry-test-topic", "test-key", "test-message");

        // DLT handler should be called after 2 failed attempts:
        boolean dltCalled = dltLatch.await(10, TimeUnit.SECONDS);
        assertTrue(dltCalled, "DLT handler should have been called");
    }
}

